import{_ as c}from"./plugin-vue_export-helper-c27b6911.js";import{r as d,o as l,c as i,a as e,b as a,e as r,f as t}from"./app-74137bf2.js";const T={},n=t('<h3 id="浏览器搜索框按下回车后发生了什么" tabindex="-1"><a class="header-anchor" href="#浏览器搜索框按下回车后发生了什么" aria-hidden="true">#</a> 浏览器搜索框按下回车后发生了什么？</h3><ol><li><code>解析URL：</code>输入url并回车后浏览器进程检查url，组装协议去构成完整的url，浏览器进程通过进程间通信（IPC）把url请求发送给网络进程。</li><li><code>缓存检查：</code>网络进程收到url请求后检查本地缓存是否有缓存，如果有则将该资源返回给浏览器进程。</li><li><code>网络进程向服务器发起网络请求：</code>① 进行DNS解析获取服务器的ip、端口；② 浏览器需要和服务器建立连接，进入TCP队列进行三次握手；③ HTTPS建立TLS连接；④ 向服务器发送HTTP请求（请求行、请求头、请求体）。</li><li><code>服务器处理请求并返回响应: </code>网络进程接收响应头和响应信息并解析响应内容。状态码内容 ① 如果是<code>301、302</code>那么就是数据重定向，从Location获取地址重新发起请求；② 如果是<code>304</code>那么就是使用本地缓存； ③ 如果是<code>200</code>，那么检测响应类型<code>Content-Type</code>,字节流类型那么提交给下载管理器进行下载；html则需要渲染页面，通知浏览器进程准备渲染进程。</li><li><code>数据传输完成：</code>TCP四次挥手断开连接。如果HTTP头部加上<code>Connection:Keep-Alive</code>，TCP就一直保持连接。保持TCP连接可以省下下次需要建立连接的时间，提示资源加载速度。</li><li><code>渲染进程接收数据：</code>渲染进程收到消息后，会和网络进程建立传输数据的“管道”，文档数据传输完成后，渲染进程会返回“确认提交”的消息给浏览器进程。</li><li><code>浏览器更新页面状态：</code>浏览器收到“确认提交”的消息后，会更新浏览器的页面状态，包括了安全状态、地址栏的 URL、前进后退的历史状态，并更新web页面，此时的web页面是空白页。</li><li><code>页面渲染：</code></li></ol><blockquote><p>a. <code>Parse HTML</code>:将HTML内容转成浏览器能够读懂的DOM树结构；<br> b. <code>Parse StyleSheet</code>： 将css样式表转化为浏览器可以理解的css树；<br> c. <code>Recalculate Style</code>: 计算出DOM每一个节点对应的具体样式；<br> d. <code>Layout</code>：DOM树与CSS树创建布局树，并计算元素的布局信息；<br> e. <code>Layer Tree</code>:对布局树进行分层，生成图层树；会生成图层情况：<code>video position:fixed canvas css动画 transform等</code>；<br> f. <code>Paint</code>：对每一个图层进行绘制；<br> g. <code>Composite Layers</code>：合并图层；</p></blockquote><h3 id="五层模型" tabindex="-1"><a class="header-anchor" href="#五层模型" aria-hidden="true">#</a> 五层模型？</h3><ol><li>物理层：使用一定的物理介质(光纤、双绞线)</li><li>数据链路层：帧同步、MAC寻址(Wi-Fi、交换机)</li><li>网络层：路由选择、IP寻址，把数据包送达目的主机<code>(IP协议)</code></li><li>传输层: 负责端到端的通信，把数据完整地送达主机里面的应用程序<code>(UDP、TCP)</code></li><li>应用层：为用户提供网络服务<code>(HTTP、HTTPS、DNS、WebSocket)</code></li></ol><h3 id="dns解析" tabindex="-1"><a class="header-anchor" href="#dns解析" aria-hidden="true">#</a> DNS解析？</h3><ol><li>DNS是什么？域名系统(<code>Domain Name System</code>)，根据域名如返回对应的<code>IP</code>。整个网络中存在着无数个服务器，每一个服务器都有它自己的唯一标识—ip地址，但是ip不好记忆，所以需要域名如<code>baidu.com</code>。域名就相当于是ip地址的别名。</li><li>作用？浏览器地址栏输入域名，会去DNS服务器上找到对应的外网IP，然后基于服务器的外网IP，找到服务器</li><li>解析过程？ ①首先会在浏览器的缓存中查找对应的IP地址，没有的话请求发送给本地DNS服务器；②在本地域名服务器缓存中查询，没有的话本地DNS服务器向根域名服务器/顶级域名服务器/权威域名服务器发送请求。③最后将返回结果保存在缓存中，便于下次使用。</li><li>前端优化:尽可能减少DNS解析需要的时间</li></ol><blockquote><p>① 把不同资源分不同的服务器部署（web服务器、图片服务器、数据服务器）<br> ② DNSPrefetch:DNS预解析，利用<code>&lt;link&gt;</code>的异步性，在GUI染过程中，同时去解析域名</p></blockquote><h3 id="udp与tcp的区别是什么" tabindex="-1"><a class="header-anchor" href="#udp与tcp的区别是什么" aria-hidden="true">#</a> UDP与TCP的区别是什么？</h3><ol><li>UDP (<code>User Datagram Protocol</code>用户数据包协议)：是一种无连接的传输层通信协议，不能保证数据可靠性，但是传输速度却非常快。</li><li>TCP(<code>Transmission Control Protocol</code>传输控制协议) ：是一种面向连接的、可靠的、基于字节流的传输层的通信协议。</li></ol><blockquote><p><code>面向连接：</code>一个完整的 TCP 连接的生命周期包括了“建立连接”、“传输数据”和“断开连接”；<br><code>可靠：</code>对于数据包丢失的情况，TCP 提供重传机制；并且有数据包排序机制，用来保证把乱序的数据包组合成一个完整的文件。<br> ① <code>建立连接:</code>是指在建立一个TCP连接时，客户端和服务器总共要发送三个数据包以确认连接的建立。<br> ② <code>传输数据：</code>接收端需要对每个数据包进行确认操作，在规定时间内没有接收到接收端反馈的确认消息，则判断为数据包丢失，并触发发送端的重发机制。<br> ③ <code>断开连接：</code>用“四次挥手”来保证双方都能断开连接。</p></blockquote><ol start="3"><li>UDP与TCP区别？</li></ol><blockquote><p>a. <code>是否面向连接：</code>UDP无连接;TCP面向连接<br> b. <code>可靠性：</code>UDP不可靠；TCP是可靠传输，重传机制、排序机制。<br> c. <code>连接对象个数：</code>UDP可以多对多；TCP只能一对一传输<br> d. <code>传输方式：</code>UDP是面向报文；TCP是面向字节流<br> e. <code>适用场景：</code>UDP适用于实时应用，如直播、视屏；TCP适用于可靠运算，如文件传输</p></blockquote><h3 id="tcp三次握手四次挥手" tabindex="-1"><a class="header-anchor" href="#tcp三次握手四次挥手" aria-hidden="true">#</a> TCP三次握手四次挥手？</h3><ol><li>状态控制码：<code>SYN：</code>发起一个新连接；<code>FIN：</code>释放一个连接；<code>ACK：</code>确定序号有效；seq序号；ack确认序号；</li><li>三次握手：为了确认双方的接收能力和发送能力是否正常。</li></ol><blockquote><p>a. 客户端向服务器发送SYN连接请求报文段和随机序号<code>SYN=1 seq=x</code>；<br> b. 服务器收到连接请求，向客户端发送SYN、ACK报文段以及随机序号<code>SYN=1 ACK=1 ack=x+1 seq=y</code>；<br> c. 客户端接收到服务端的确认应答后进入连接建立的状态，向服务端发送一个ACK确认报文段<code>ACK=1 ack=y+1</code>；</p></blockquote><ol start="3"><li>四次挥手：当服务器端收到FIN报文时，很可能并不会立即关闭链接。所以只能先回复一个ACK报文，告诉客户端我收到了，等到服务器端所有的报文都发送完了，才能发送FIN报文，因此不能一起发送，故需要四步握手。</li></ol><blockquote><p>a. 客户端认为数据发送完成，它会向服务端发送连接释放请求 <code>FIN=1 seq=x</code>；<br> b. 服务端收到连接释放请求后，会发送<code>ACK=1 ack=x+1</code>，然后服务端继续发送数据给客户端；<br> c. 服务端传输完毕后会向客户端发送连接释放请求<code>FIN=1 seq=y</code>，然后服务端便进入<code>LAST-ACK</code>状态；<br> d. 端收到释放请求后，向服务端发送确认应答<code>ACK=1 ack=y+1</code>，此时客户端进入<code>TIME-WAIT</code>状态，若该时间段内没有服务端的重发请求的话，就进入<code>CLOSED</code>状态，服务端收到确认应答后，也便进入<code>CLOSED</code>状态</p></blockquote><h3 id="常见的请求方法" tabindex="-1"><a class="header-anchor" href="#常见的请求方法" aria-hidden="true">#</a> 常见的请求方法？</h3><ol><li><code>GET：</code>向服务器获取数据</li><li><code>POST：</code>将实体提交给指定的资源，通常是修改</li><li><code>HEAD：</code>获取报文首部，不返回报文主体</li><li><code>OPTION：</code>询问支持的方法，通常用作跨域请求</li><li><code>DELETE：</code>删除服务器的对象</li><li><code>PUT：</code>上传文件，更新数据</li><li><code>CONNECT：</code>要求在与代理服务器通信时建立隧道，使用隧道进行 TCP 通信；</li></ol><h3 id="get与post的区别是什么" tabindex="-1"><a class="header-anchor" href="#get与post的区别是什么" aria-hidden="true">#</a> get与post的区别是什么？</h3><ol><li><code>作用上：</code>get请求主要用来向服务器请求资源，post请求主要用来向服务器发送数据</li><li><code>参数上：</code>GET参数通过URL传递，POST放在<code>Request body</code>中；由于url地址长度有限制,GET请求在url中传送的参数是有长度限制的，而 POST 没有。</li><li><code>安全上：</code>GET比POST更不安全，因为参数直接暴露在url上，所以不能用来传递敏感信息；</li><li><code>编码方式：</code>GET 请求只能进行url编码，而POST支持多种编码方式。</li><li><code>缓存上：</code>GET 请求参数会被完整保留在浏览器历史记录里，而POST中的参数不会被保留；GET 产生的url地址可以被Bookmark，而POST不可以。</li></ol><h3 id="http状态码" tabindex="-1"><a class="header-anchor" href="#http状态码" aria-hidden="true">#</a> HTTP状态码？</h3><ol><li>2XX: <code>200（OK）</code>：表示请求成功；<code>204（No content）</code>：表示请求成功，但响应报文不含实体的主体部分；<code>206（Partial Content）</code>：进行范围请求</li><li>3XX：<code>301（moved permanently）</code>：永久重定向; <code>302（found）</code>：临时重定向，如跳转到登录页面; <code>304（not modified）</code>：未修改，使用浏览器的本地缓存</li><li>4XX: <code>400（bad request）</code>:请求报文有错误; <code>401（unauthorized）</code>：未登录；<code>403（forbidden）</code>：没有足够的权限；<code>404（not found）</code>：服务器没有找到资源</li><li>5XX: <code>500（internal sever error）</code>:服务器错误; <code>501（Not Implemented）</code>：表示服务器不支持当前请求所需要的某个功能; <code>503（service unavailable）</code>：服务目前无法使用</li></ol><h3 id="http" tabindex="-1"><a class="header-anchor" href="#http" aria-hidden="true">#</a> HTTP？</h3><ol><li>是什么：HTTP（<code>Hypertext Transfer Protocol</code>）超文本协议传输，是应用层的协议，定义了客户端与服务器之间交换报文的格式与方式，默认是80端口，使用TCP作为传输层协议，保证数据的可靠性。</li><li>请求报文：① 请求行<code>GET /index.html?username=XX HTTP/1.1</code>（请求的方式、资源的路径、协议的版本）；② 请求头（用来告诉服务器我们浏览器的信息）；③ 请求体（post请求通过请求体来发送数据）</li><li>响应报文：① 响应⾏<code>HTTP/1.1 200 OK </code>由网络协议版本，状态码和状态码的原因短语组成；② 响应头（用来告诉浏览器响应的信息）；③ 响应体（服务器响应的数据）</li><li>优点：a. 简单快速：客户向服务器请求服务时，只需传送请求方法和路径；b. 无状态：是无状态协议，这里的状态是指通信过程的上下文信息；c. 无连接：无连接就是限制每次连接只处理一个请求；d. 灵活：HTTP 允许传输任意类型的数据对象。正在传输的类型由 Content-Type 加以标记。</li><li>缺点：a. 无状态：HTTP 是一个无状态的协议，HTTP 服务器不会保存关于客户的任何信息； b. 明文传输：协议中的报文使用的是文本形式，这就直接暴露给外界，不安全； c. 安全：通信使用明文（不加密），内容可能会被窃听；不验证通信方的身份，因此有可能遭遇伪装；</li></ol><h3 id="https" tabindex="-1"><a class="header-anchor" href="#https" aria-hidden="true">#</a> HTTPS？</h3><ol><li>是什么：超文本传输安全协议，它经由HTTP进行通信，并利用<code>TLS/SSL</code>来加密数据包。目的是为了提供对网站的身份认证以及保证数据的私密性。</li><li>HTTPS 所有的安全核心都在<code>安全层</code>，安全层有两个主要的职责：对发起HTTP请求的数据进行加密操作和对接收到 HTTP 的内容进行解密操作。</li><li><code>数字证书</code>：一个是通过数字证书向浏览器证明服务器的身份，另一个是数字证书里面包含了服务器公钥。</li><li><code>对称加密</code>：指加密和解密都使用的是相同的密钥。协商秘钥的过程容易被窃取。</li><li><code>非对称加密</code>：服务端用私钥加密的内容，浏览器可以通过公钥进行解密。只用非对称加密的效率太低，服务器发送给浏览器的数据需要使用公钥解密，黑客也是可以获取得到公钥的，这样就不能保证服务器端数据的安全了。</li><li>怎么传输数据？ 搭配使用两种加密，用非对称加密交换密钥、对称加密传输内容。</li><li>过程？</li></ol><blockquote><p>ⅰ. 浏览器向服务器发送对称加密套件列表、非对称加密套件列表和随机数 <code>client-random</code>；<br> ⅱ. 服务器向浏览器发送选择的加密套件、<code>service-random</code> 和数字证书；<br> ⅲ. 浏览器验证数据证书有效性，生成随机数 <code>pre-master</code>，然后利用公钥对<code>pre-master</code>加密，向服务器发送加密后的数据，黑客不知道对应的私钥，所以黑客不能解密出<code>pre-master</code>；<br> ⅳ. 服务器拿出自己的私钥，解密出<code>pre-master</code>数据，并返回确认消息；<br> ⅴ. 服务器和浏览器就有了共同的 <code>client-random、service-random 和 pre-master</code>，然后服务器和浏览器会使用这三组随机数生成对称密钥。</p></blockquote><h3 id="http与https区别" tabindex="-1"><a class="header-anchor" href="#http与https区别" aria-hidden="true">#</a> HTTP与HTTPS区别？</h3><ol><li>HTTP是超文本协议传输，定义了客户端与服务器之间交换报文的格式与方式，默认是80端口，使用TCP作为传输层协议，保证数据的可靠性;</li><li>HTTPS是超文本传输安全协议，它经由http进行通信，并利用TLS/SSL来加密数据包。目的是为了提供对网站的身份认证以及保证数据的私密性；</li><li><code>端口</code>：HTTPS是443、HTTP是80；</li><li><code>传输方式</code>：HTTPS是加密传输、HTTP是明文传输</li><li><code>传输速度</code>：HTTPS传输速度较慢，除了TCP三次握手，还有SSL握手9个包；</li><li><code>数字证书</code>：HTTPS需要数字证书，费用较高；</li><li><code>安全性</code>：HTTP是无状态的，HTTPS有SSL和HTTP构建的可进行加密传输、身份认证的网络协议，比HTTP更加安全。</li></ol><h3 id="链接" tabindex="-1"><a class="header-anchor" href="#链接" aria-hidden="true">#</a> 链接</h3>',32),h={href:"https://time.geekbang.org/column/article/117637",target:"_blank",rel:"noopener noreferrer"};function s(P,b){const o=d("ExternalLinkIcon");return l(),i("div",null,[n,e("p",null,[e("a",h,[a("浏览器工作原理与实践"),r(o)])])])}const S=c(T,[["render",s],["__file","输入url到页面展示后发生什么.html.vue"]]);export{S as default};
